<div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="第一层缓存-cachedinstances" tabindex="-1"><a class="header-anchor" href="#第一层缓存-cachedinstances"><span>第一层缓存: cachedInstances</span></a></h4>
